class Solution:
    def printVertically(self, s):
        words = s.split()
        max_len = max(len(w) for w in words)
        result = []
        for r in range(max_len):
            row = ''.join(w[r] if r < len(w) else ' ' for w in words)
            result.append(row.rstrip())
        return result

