solutions.javascript:
var printVertically = function(s) {
    const words = s.split(' ');
    const maxLen = Math.max(...words.map(w => w.length));
    const res = [];
    for (let i = 0; i < maxLen; i++) {
        let row = words.map(w => i < w.length ? w[i] : ' ').join('');
        res.push(row.replace(/\s+$/, ''));
    }
    return res;
};
